/* --- normalize: s/c/x → q/o/e (app.js bu formatı bekliyor) --- */
function _norm(arr) {
  return arr.map(function(s) {
    var out = { q: s.s || s.q, o: s.c || s.o, a: s.a };
    if (s.x || s.e) out.e = s.x || s.e;
    if (s.img) out.img = s.img;
    if (s.audio) out.audio = s.audio;
    return out;
  });
}

/* --- merge --- */
for (const [kat, seviyeler] of Object.entries(SORU_EK)) {
  if (!SORU_HAVUZU[kat]) {
    SORU_HAVUZU[kat] = {};
  }
  if (seviyeler.hepsi) {
    SORU_HAVUZU[kat].hepsi = [...(SORU_HAVUZU[kat].hepsi || []), ..._norm(seviyeler.hepsi)];
  }
}
Object.assign(KATEGORI_BILGI, KATEGORI_BILGI_EK);
